def binary_search_standard(arr, target):
    """
    Standart ikili arama: Hedefin herhangi bir indeksini döndürür. Bulunamazsa -1.
    """
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1


def binary_search_first_occurrence(arr, target):
    """
    İlk oluşumu bulan ikili arama: Hedefin ilk oluşumunun indeksini döndürür. Bulunamazsa -1.
    """
    left, right = 0, len(arr) - 1
    ans = -1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            ans = mid
            right = mid - 1  # Daha önceki bir oluşumu ara
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return ans


