def binary_search_lower_bound(arr, target):
    """
    Alt sınır (Lower Bound) ikili araması: Hedefe eşit veya ondan büyük ilk öğenin indeksini döndürür.
    Tüm öğeler hedeften küçükse len(arr) döndürür. (Python'daki bisect_left'e benzer)
    """
    left, right = 0, len(arr) - 1
    ans = len(arr)  # Tüm öğeler hedeften küçükse
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] >= target:
            ans = mid
            right = mid - 1  # Daha küçük bir indeks ara
        else:
            left = mid + 1
    return ans


def binary_search_upper_bound(arr, target):
    """
    Üst sınır (Upper Bound) ikili araması: Hedeften kesinlikle büyük ilk öğenin indeksini döndürür.
    Tüm öğeler hedefe eşit veya ondan küçükse len(arr) döndürür. (Python'daki bisect_right'a benzer)
    """
    left, right = 0, len(arr) - 1
    ans = len(arr)  # Tüm öğeler hedefe eşit veya ondan küçükse
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] > target:
            ans = mid
            right = mid - 1  # Daha küçük bir indeks ara
        else:  # arr[mid] <= target
            left = mid + 1
    return ans


def binary_search_peak_element(arr):
    """
    Tepe öğesi (Peak Element) ikili araması: Önce artan sonra azalan bir dizide (veya genel olarak bir yerel tepe) tepe noktasının indeksini döndürür.
    """
    if not arr:
        return -1
    if len(arr) == 1:
        return 0

    left, right = 0, len(arr) - 1
    while left < right:
        mid = left + (right - left) // 2
        if arr[mid] < arr[mid + 1]:
            # Artan yokuşta, tepe sağ tarafta
            left = mid + 1
        else:
            # Azalan yokuşta veya tepedeyiz
            # Tepe 'mid' olabilir veya sol tarafta olabilir
            right = mid
    return left  # veya right, ikisi de aynıdır


def binary_search_rotated_array(arr, target):
    """
    Döndürülmüş sıralı dizide ikili arama: Döndürülmüş sıralı bir dizide hedefi arar. Bulunamazsa -1.
    """
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            return mid

        # Sol yarım sıralı mı kontrol et
        if arr[left] <= arr[mid]:
            if arr[left] <= target < arr[mid]:
                right = mid - 1
            else:
                left = mid + 1
        # Sağ yarım sıralı olmalı
        else:
            if arr[mid] < target <= arr[right]:
                left = mid + 1
            else:
                right = mid - 1
    return -1


def binary_search_sqrt_integer(x):
    """
    Tam sayı karekök ikili araması: Negatif olmayan bir x sayısının katı olarak karekökünü (floor(sqrt(x))) döndürür.
    """
    if x < 0:
        raise ValueError("Girdi negatif olmayan bir tam sayı olmalı")
    if x == 0:
        return 0

    left, right = 1, x
    ans = 0
    while left <= right:
        mid = left + (right - left) // 2
        if mid * mid <= x:
            ans = mid
            left = mid + 1
        else:
            right = mid - 1
    return ans


def binary_search_on_answer_min_template(low, high, check_function):
    """
    Cevap üzerinde ikili arama (Minimum hedef): Belirli bir koşulu (check_function) sağlayan en küçük değeri bulmak için genel şablon.
    check_function(val): val değeri koşulu sağlıyorsa True, aksi takdirde False döner.
    Monotonluk: Eğer check_function(X) True ise, Y > X için check_function(Y) de True'dur.
    """
    ans = high  # Veya problemi özel bir başlangıç değeri
    while low <= high:
        mid = low + (high - low) // 2
        if check_function(mid):
            ans = mid
            high = mid - 1  # Daha küçük bir olası cevap dene
        else:
            low = mid + 1
    return ans


def binary_search_on_answer_max_template(low, high, check_function):
    """
    Cevap üzerinde ikili arama (Maksimum hedef): Belirli bir koşulu (check_function) sağlayan en büyük değeri bulmak için genel şablon.
    check_function(val): val değeri koşulu sağlıyorsa True, aksi takdirde False döner.
    Monotonluk: Eğer check_function(X) True ise, Y < X için check_function(Y) de True'dur.
    """
    ans = low  # Veya probleme özel bir başlangıç değeri
    while low <= high:
        mid = low + (high - low) // 2
        if check_function(mid):  # mid geçerli bir aday ise
            ans = mid
            low = mid + 1  # Daha büyük bir olası cevap dene
        else:
            high = mid - 1
    return ans
